
-- ═══════════════════════════════════════════════════════════════
-- Table: app_themes — stores all theme definitions (built-in + custom)
-- ═══════════════════════════════════════════════════════════════
CREATE TABLE public.app_themes (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  theme_key TEXT NOT NULL UNIQUE,
  label TEXT NOT NULL,
  description TEXT,
  is_system BOOLEAN NOT NULL DEFAULT false,
  is_enabled BOOLEAN NOT NULL DEFAULT true,
  sort_order INTEGER NOT NULL DEFAULT 0,
  css_vars JSONB NOT NULL DEFAULT '{}',
  dark_css_vars JSONB NOT NULL DEFAULT '{}',
  created_by TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_by TEXT,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX idx_app_themes_enabled ON public.app_themes (is_enabled);

-- ═══════════════════════════════════════════════════════════════
-- Table: user_theme_preferences — per-user theme selection
-- ═══════════════════════════════════════════════════════════════
CREATE TABLE public.user_theme_preferences (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE UNIQUE,
  theme_key TEXT NOT NULL DEFAULT 'executive-slate',
  is_dark BOOLEAN NOT NULL DEFAULT false,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX idx_user_theme_prefs_user ON public.user_theme_preferences (user_id);

